var raw = $input.first().json;
var body = raw.body || raw;
var data = body.data || body;
var tenantId = String(body.tenantId || data.tenantId || '');

function esc(v) {
  return v == null ? '' : String(v).replace(/'/g, "''");
}

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) {
  throw new Error('Invalid tenantId');
}

if (!data.memberId || !data.type || !data.dateDebut || !data.dateFin) {
  throw new Error('memberId, type, dateDebut, dateFin are required');
}

// Validation des types de congé conformes au droit français
var typesValides = ['cp', 'rtt', 'maladie', 'maternite', 'paternite', 'sans_solde', 'familial', 'formation', 'deces', 'mariage', 'demenagement', 'enfant_malade', 'autre'];
var typeConge = String(data.type).toLowerCase();
if (typesValides.indexOf(typeConge) === -1) {
  typeConge = 'autre';
}

// Calcul automatique des jours ouvrés entre les 2 dates
var joursPris = data.joursPris;
if (joursPris == null || joursPris === '') {
  var d1 = new Date(data.dateDebut);
  var d2 = new Date(data.dateFin);
  if (d2 < d1) throw new Error('dateFin doit être >= dateDebut');
  var count = 0;
  var current = new Date(d1);
  while (current <= d2) {
    var day = current.getDay();
    if (day !== 0 && day !== 6) count++; // Exclure samedi/dimanche
    current.setDate(current.getDate() + 1);
  }
  joursPris = count;
}

// Validation: congé maternité min 16 semaines, paternité 25 jours
if (typeConge === 'maternite' && joursPris < 80) {
  // Avertissement dans le commentaire mais on laisse passer
}

var query = "INSERT INTO rh_conges (tenant_id, member_id, type, date_debut, date_fin, jours_pris, motif, statut, approuve_par, date_reponse, commentaire) VALUES (" +
  "'" + esc(tenantId) + "'," +
  "'" + esc(data.memberId) + "'," +
  "'" + esc(typeConge) + "'," +
  "'" + esc(data.dateDebut) + "'," +
  "'" + esc(data.dateFin) + "'," +
  joursPris + "," +
  (data.motif ? "'" + esc(data.motif) + "'" : "NULL") + "," +
  "'" + esc(data.statut || 'en_attente') + "'," +
  (data.approuvePar ? "'" + esc(data.approuvePar) + "'" : "NULL") + "," +
  (data.dateReponse ? "'" + esc(data.dateReponse) + "'" : "NULL") + "," +
  (data.commentaire ? "'" + esc(data.commentaire) + "'" : "NULL") +
  ") RETURNING *";

return [{json: {query: query}}];
